-- ============================================================
-- Quiz Seed: 2 Kings Chapters 11–20
-- Target table: chapter_quizzes
-- Difficulties: kids (3 Qs), teens (5 Qs), adults (8 Qs)
-- correct_answer is always 'a'
-- ============================================================

-- ═══════════════════════════════════════════
-- CHAPTERS 11 – 15
-- ═══════════════════════════════════════════

-- ═══ 2 Kings Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 11, 'kids', 1, 'Who tried to kill all the royal children and became queen?', 'Athaliah', 'Jezebel', 'Deborah', 'Miriam', 'a', 'When Athaliah saw that her son was dead, she arose and destroyed all the seed royal (2 Kings 11:1).'),
('2 Kings', 11, 'kids', 2, 'Who hid the baby Joash in the temple for six years?', 'Jehosheba the priest''s wife', 'The queen mother', 'A servant girl', 'Elisha the prophet', 'a', 'Jehosheba took Joash and hid him in the house of the LORD for six years (2 Kings 11:3).'),
('2 Kings', 11, 'kids', 3, 'What happened to Queen Athaliah at the end of the chapter?', 'She was killed', 'She fled to Egypt', 'She repented and became a prophetess', 'She was put in prison', 'a', 'They laid hands on her; and she went by the way by the which the horses came into the king''s house: and there was she slain (2 Kings 11:16).'),
-- Teens
('2 Kings', 11, 'teens', 1, 'How old was Joash when he was crowned king by Jehoiada the priest?', 'Seven years old', 'Twelve years old', 'Five years old', 'Ten years old', 'a', 'Joash was seven years old when he began to reign (2 Kings 11:21).'),
('2 Kings', 11, 'teens', 2, 'Who organised the coup that overthrew Athaliah and crowned Joash?', 'Jehoiada the priest', 'The army commander', 'The prophet Elisha', 'The tribe of Levi', 'a', 'Jehoiada the priest commanded the captains of the hundreds to bring Joash out, and they made him king (2 Kings 11:9-12).'),
('2 Kings', 11, 'teens', 3, 'What was placed in Joash''s hand at his coronation?', 'The testimony', 'A golden sceptre', 'The ark of the covenant', 'A sword', 'a', 'He brought forth the king''s son, and put the crown upon him, and gave him the testimony; and they made him king (2 Kings 11:12).'),
('2 Kings', 11, 'teens', 4, 'What covenant did Jehoiada make on the day of the coronation?', 'A covenant between the LORD, the king, and the people', 'A covenant of peace with the surrounding nations', 'A covenant to rebuild the temple', 'A covenant to destroy all idols in Israel', 'a', 'Jehoiada made a covenant between the LORD and the king and the people, that they should be the LORD''s people (2 Kings 11:17).'),
('2 Kings', 11, 'teens', 5, 'What did the people do to the temple of Baal after Athaliah''s overthrow?', 'They broke it down and slew its priest Mattan', 'They converted it into a store house', 'They sealed it shut', 'They burned it to the ground', 'a', 'All the people went into the house of Baal, and brake it down; his altars and his images brake they in pieces thoroughly, and slew Mattan the priest of Baal (2 Kings 11:18).'),
-- Adults
('2 Kings', 11, 'adults', 1, 'Who was Jehosheba, the woman who hid young Joash?', 'The daughter of King Joram and sister of Ahaziah', 'The wife of the high priest and a prophetess', 'A Levite nurse appointed by Jehoiada', 'The mother of Jehoiada', 'a', 'Jehosheba, the daughter of king Joram, sister of Ahaziah, took Joash the son of Ahaziah (2 Kings 11:2).'),
('2 Kings', 11, 'adults', 2, 'How long was Athaliah''s reign before she was overthrown?', 'Six years', 'Seven years', 'Four years', 'Ten years', 'a', 'Athaliah did reign over the land for six years while Joash was hidden (2 Kings 11:3).'),
('2 Kings', 11, 'adults', 3, 'What instructions did Jehoiada give regarding the guards'' Sabbath rotations?', 'Two parts to keep the king''s house and one part at the gate Sur', 'One third to guard the temple gate, one third at the palace gate, one third at the gate behind the guard', 'All guards to assemble at the temple at the third hour', 'The incoming guard to surround Joash and the outgoing to stand at the wall', 'a', 'Jehoiada commanded the captains: a third part...shall keep the watch of the king''s house...and a third part at the gate Sur (2 Kings 11:5-6).'),
('2 Kings', 11, 'adults', 4, 'What specific command was given to anyone who followed Athaliah into the temple at the moment of the coup?', 'He that followeth her, kill with the sword', 'He that entereth the temple shall be bound', 'Seize him but do not kill him inside the holy place', 'Warn him once before striking him down', 'a', 'He that followeth her kill with the sword. For the priest had said, Let her not be slain in the house of the LORD (2 Kings 11:15).'),
('2 Kings', 11, 'adults', 5, 'What did Athaliah cry out when she saw Joash crowned?', 'Treason, Treason', 'God forbid, God forbid', 'Death to the usurper', 'Where is my army', 'a', 'When Athaliah heard the noise of the guard and of the people, she came to the people into the temple of the LORD. And when she looked, behold, the king stood by a pillar, as the manner was, and she rent her clothes, and cried, Treason, Treason (2 Kings 11:13-14).'),
('2 Kings', 11, 'adults', 6, 'Through what gate was Athaliah taken out to be executed?', 'The horse gate', 'The water gate', 'The sheep gate', 'The valley gate', 'a', 'She went by the way by the which the horses came into the king''s house: and there was she slain (2 Kings 11:16).'),
('2 Kings', 11, 'adults', 7, 'What was the condition of the city described after Athaliah was slain?', 'The city was in quiet', 'The city mourned for seven days', 'The people shouted for a full day', 'The city was set on fire', 'a', 'And all the people of the land rejoiced, and the city was in quiet (2 Kings 11:20).'),
('2 Kings', 11, 'adults', 8, 'What theological significance does the survival of Joash represent in redemptive history?', 'The preservation of the Davidic line through which the Messiah would come', 'The proof that God favoured the tribe of Judah above all others', 'The fulfilment of Elijah''s prophecy against the house of Ahab', 'The establishment of a priestly monarchy in Jerusalem', 'a', 'God preserved the line of David — Joash was a descendant through whom the Messianic promise of 2 Samuel 7 would continue, as Athaliah''s near extinction of the royal seed threatened the covenant (2 Kings 11:2-3).');

-- ═══ 2 Kings Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 12, 'kids', 1, 'What did King Joash want to repair?', 'The house of the LORD', 'The city walls of Jerusalem', 'The palace of the king', 'The roads to the city', 'a', 'Joash said to the priests, All the money...let them repair the breaches of the house (2 Kings 12:5).'),
('2 Kings', 12, 'kids', 2, 'What did Jehoiada the priest make to collect money for the temple repairs?', 'A chest with a hole in the lid', 'A golden bowl at the altar', 'A large basket at the gate', 'A treasury room in the temple', 'a', 'Jehoiada the priest took a chest, and bored a hole in the lid of it, and set it beside the altar (2 Kings 12:9).'),
('2 Kings', 12, 'kids', 3, 'How did King Joash die?', 'He was killed by his own servants', 'He died of old age in his palace', 'He was killed in battle with Assyria', 'He was struck by lightning', 'a', 'His servants arose, and made a conspiracy, and slew Joash in the house of Millo (2 Kings 12:20).'),
-- Teens
('2 Kings', 12, 'teens', 1, 'How old was Joash when he became king and how long did he reign in Jerusalem?', 'Seven years old; forty years', 'Ten years old; thirty years', 'Five years old; twenty years', 'Twelve years old; fifteen years', 'a', 'Jehoash was seven years old when he began to reign. In Jerusalem he reigned forty years (2 Kings 12:1).'),
('2 Kings', 12, 'teens', 2, 'What did Jehoash instruct the priests to do with all the money brought into the house of the LORD?', 'Repair the breaches of the house wherever any breach shall be found', 'Divide it equally between the priests and the temple workers', 'Send it to the king''s treasury for safekeeping', 'Use it to buy sacrifices for the altar', 'a', 'Let the priests take it to them, every man of his acquaintance: and let them repair the breaches of the house, wheresoever any breach shall be found (2 Kings 12:5).'),
('2 Kings', 12, 'teens', 3, 'Why did King Joash rebuke the priests in the twenty-third year of his reign?', 'They had not repaired the breaches of the house', 'They had stolen money from the chest', 'They had stopped offering sacrifices', 'They had built a new altar to Baal', 'a', 'In the three and twentieth year of king Jehoash the priests had not repaired the breaches of the house (2 Kings 12:6).'),
('2 Kings', 12, 'teens', 4, 'How did Hazael king of Syria threaten Jerusalem?', 'He came up and set his face to go up to Jerusalem', 'He sent a great army to besiege the city for three years', 'He cut off the water supply to the city', 'He burned the temple treasury', 'a', 'Hazael king of Syria went up and fought against Gath, and took it: and Hazael set his face to go up to Jerusalem (2 Kings 12:17).'),
('2 Kings', 12, 'teens', 5, 'How did Joash persuade Hazael not to attack Jerusalem?', 'He gave him all the hallowed things and the gold of the temple and palace treasuries', 'He promised to pay tribute every year', 'He surrendered two cities', 'He sent his daughter to Hazael as a wife', 'a', 'Jehoash took all the hallowed things...and all the gold that was found in the treasures of the house of the LORD, and in the king''s house, and sent it to Hazael king of Syria: and he went away from Jerusalem (2 Kings 12:18).'),
-- Adults
('2 Kings', 12, 'adults', 1, 'What was the overall spiritual assessment of Joash''s reign despite his good deeds?', 'He did that which was right in the sight of the LORD all his days, taught by Jehoiada, but the high places were not taken away', 'He departed from the LORD in his old age and worshipped idols', 'He was fully righteous with no fault recorded', 'He provoked the LORD more than any king before him', 'a', 'Jehoash did that which was right in the sight of the LORD all his days wherein Jehoiada the priest instructed him. But the high places were not taken away (2 Kings 12:2-3).'),
('2 Kings', 12, 'adults', 2, 'What reform did Jehoiada institute regarding the new collection chest?', 'The priests that kept the door put therein all the money that was brought into the house of the LORD, and the king''s scribe counted it', 'The Levites carried the chest to every gate to collect offerings weekly', 'Only the high priest could open the chest at the new moon', 'The chest was sealed and opened only at the year of jubilee', 'a', 'The priests that kept the door put therein all the money that was brought into the house of the LORD. And when they saw that there was much money in the chest...the king''s scribe and the high priest...told the money (2 Kings 12:9-10).'),
('2 Kings', 12, 'adults', 3, 'What does the account of the temple repairs say about the honesty of the workmen?', 'They dealt faithfully so no reckoning was made with them', 'They were required to submit weekly accounts to the priest', 'Several were found dishonest and dismissed', 'They were paid double for their honesty', 'a', 'They reckoned not with the men, into whose hand they delivered the money to be bestowed on workmen: for they dealt faithfully (2 Kings 12:15).'),
('2 Kings', 12, 'adults', 4, 'What items were NOT repaired with the collected money according to verse 13?', 'Bowls of silver, snuffers, basons, trumpets, or any vessels of gold or silver', 'The great bronze pillars Jachin and Boaz', 'The altar of incense inside the temple', 'The ark of the covenant''s carrying poles', 'a', 'Howbeit there were not made for the house of the LORD bowls of silver, snuffers, basons, trumpets, any vessels of gold, or vessels of silver, of the money that was brought into the house of the LORD (2 Kings 12:13).'),
('2 Kings', 12, 'adults', 5, 'Who were the two servants of Joash who conspired against him and where was he killed?', 'Jozachar the son of Shimeath and Jehozabad the son of Shomer; in the house of Millo going down to Silla', 'Ahishar and Adoniram; in the palace garden', 'Benaiah and Zadok; at the gate of the guard', 'Two unnamed Philistine captives; in the dungeon', 'a', 'Jozachar the son of Shimeath, and Jehozabad the son of Shomer, his servants, smote him, and he died; and they buried him with his fathers in the city of David: and Amaziah his son reigned in his stead (2 Kings 12:21).'),
('2 Kings', 12, 'adults', 6, 'How was the money that passed through the priests'' hands used differently from the guilt and sin offerings?', 'The trespass money and sin offerings were the priests'' own; only the other money went to the house repair', 'The priests received none of the guilt money as it was all sent to Hazael', 'Both types went equally to repairs', 'The priests could only use guilt money for their own food', 'a', 'The trespass money and sin money was not brought into the house of the LORD: it was the priests'' (2 Kings 12:16).'),
('2 Kings', 12, 'adults', 7, 'Where was Joash buried and who succeeded him?', 'With his fathers in the city of David; Amaziah his son', 'In Samaria with the kings of Israel; Jehoahaz his son', 'Outside the city wall as a dishonoured king; Jotham', 'In the valley of Jehoshaphat; Uzziah', 'a', 'They buried him with his fathers in the city of David: and Amaziah his son reigned in his stead (2 Kings 12:21).'),
('2 Kings', 12, 'adults', 8, 'What broader theological tension does chapter 12 reveal about Joash''s reign?', 'He was entirely dependent on Jehoiada for his faithfulness, foreshadowing his later apostasy after the priest''s death as recorded in 2 Chronicles 24', 'He proved that a godly king alone can maintain the covenant without priests', 'He showed that material prosperity always follows temple maintenance', 'He demonstrated that political alliances are acceptable when the nation is threatened', 'a', 'Joash did right all his days wherein Jehoiada the priest instructed him (2 Kings 12:2), and 2 Chronicles 24:17-18 records that after Jehoiada died, Joash abandoned the house of the LORD — showing his faithfulness was not self-sustained.');

-- ═══ 2 Kings Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 13, 'kids', 1, 'What amazing thing happened when a dead man touched Elisha''s bones?', 'The man came back to life', 'The bones turned to gold', 'The man began to prophesy', 'The ground shook', 'a', 'When the man was let down, and touched the bones of Elisha, he revived, and stood up on his feet (2 Kings 13:21).'),
('2 Kings', 13, 'kids', 2, 'Who was the king of Israel when Elisha died?', 'Joash the son of Jehoahaz', 'Jeroboam', 'Menahem', 'Pekah', 'a', 'Now Elisha was fallen sick of his sickness whereof he died. And Joash the king of Israel came down unto him (2 Kings 13:14).'),
('2 Kings', 13, 'kids', 3, 'What did Elisha tell Joash to take and strike the ground with?', 'Arrows', 'A sword', 'A rod', 'Stones', 'a', 'Elisha said, Take the arrows. And he took them. And he said unto the king of Israel, Smite upon the ground (2 Kings 13:18).'),
-- Teens
('2 Kings', 13, 'teens', 1, 'Who was the father of Joash (Jehoash) king of Israel?', 'Jehoahaz', 'Jehu', 'Jeroboam', 'Ahab', 'a', 'In the thirty and seventh year of Joash king of Judah began Jehoash the son of Jehoahaz to reign over Israel (2 Kings 13:10).'),
('2 Kings', 13, 'teens', 2, 'What did Elisha tell Joash the arrows he shot eastward represented?', 'The arrow of the LORD''s deliverance and the arrow of deliverance from Syria', 'Victory over all surrounding nations', 'The destruction of the house of Ahab', 'The restoration of all Israel''s lost territories', 'a', 'Elisha said, The arrow of the LORD''s deliverance, and the arrow of deliverance from Syria: for thou shalt smite the Syrians in Aphek, till thou have consumed them (2 Kings 13:17).'),
('2 Kings', 13, 'teens', 3, 'How many times did Joash strike the ground with the arrows, and why was Elisha angry?', 'Three times; he should have struck five or six times', 'Five times; he should have struck seven times', 'Two times; he should have struck at least four', 'Four times; he should have struck only once', 'a', 'He smote thrice, and stayed. And the man of God was wroth with him, and said, Thou shouldest have smitten five or six times (2 Kings 13:18-19).'),
('2 Kings', 13, 'teens', 4, 'What title did Joash king of Israel call Elisha when he was dying?', 'My father, my father, the chariot of Israel, and the horsemen thereof', 'Prophet of the LORD, servant of God', 'The man of God and holy one of Israel', 'Teacher, seer, and lamp of Judah', 'a', 'Joash came down unto him, and wept over his face, and said, O my father, my father, the chariot of Israel, and the horsemen thereof (2 Kings 13:14).'),
('2 Kings', 13, 'teens', 5, 'Despite the wickedness of Israel, why did God show compassion and not destroy them in Jehoahaz''s time?', 'Because of his covenant with Abraham, Isaac, and Jacob', 'Because Jehoahaz cried to the LORD and God heard his prayer', 'Because Elisha interceded for the nation', 'Because the people repented at the preaching of a prophet', 'a', 'The LORD was gracious unto them, and had compassion on them, and had respect unto them, because of his covenant with Abraham, Isaac, and Jacob (2 Kings 13:23).'),
-- Adults
('2 Kings', 13, 'adults', 1, 'How many horsemen and chariots were left to Jehoahaz by the end of Syrian oppression?', 'Fifty horsemen, ten chariots, and ten thousand footmen', 'A hundred horsemen, fifty chariots, and fifty thousand footmen', 'No cavalry at all; only foot soldiers remained', 'Two hundred horsemen and twenty chariots', 'a', 'There was not left to Jehoahaz but fifty horsemen, and ten chariots, and ten thousand footmen; for the king of Syria had destroyed them, and had made them like the dust by threshing (2 Kings 13:7).'),
('2 Kings', 13, 'adults', 2, 'What deliverer did God provide for Israel during Jehoahaz''s reign in response to his supplication?', 'A saviour so that they went out from under the hand of the Syrians', 'Elisha who performed a miracle that routed the Syrian army', 'A coalition with Judah that drove out Syria', 'An angel who destroyed the Syrian camp', 'a', 'The LORD gave Israel a saviour, so that they went out from under the hand of the Syrians (2 Kings 13:5).'),
('2 Kings', 13, 'adults', 3, 'What was the sin of Jehoahaz that is specifically named?', 'He walked in the sins of Jeroboam the son of Nebat, who made Israel to sin; he departed not therefrom', 'He sacrificed his children to Molech', 'He made an alliance with the king of Syria', 'He removed the Levites from the temple service', 'a', 'He walked in the sins of Jeroboam the son of Nebat, which made Israel to sin; he departed not therefrom (2 Kings 13:2).'),
('2 Kings', 13, 'adults', 4, 'What remained in Samaria as part of the degraded state of Israel''s worship?', 'There remained the grove also in Samaria', 'The golden calves set up by Jeroboam at Dan and Bethel', 'An Asherah pole installed by Jezebel in the temple', 'A high place dedicated to Chemosh', 'a', 'There remained the grove also in Samaria (2 Kings 13:6).'),
('2 Kings', 13, 'adults', 5, 'What does the miraculous revival at Elisha''s tomb foreshadow theologically?', 'The resurrection power of God that would ultimately be fully revealed in Christ''s own resurrection', 'That Israel would be spiritually revived in the last days', 'That Elisha was greater than Elijah', 'That touching holy objects brings life', 'a', 'The dead man revived and stood up on his feet upon touching Elisha''s bones (2 Kings 13:21), prefiguring the life-giving power that would be perfectly displayed in the resurrection of Christ (cf. John 11:25).'),
('2 Kings', 13, 'adults', 6, 'How many times did Joash defeat Syria, consistent with the three strikes of the arrows?', 'Three times', 'Five times', 'Once decisively', 'Seven times', 'a', 'Joash the son of Jehoahaz took again out of the hand of Benhadad the son of Hazael the cities...Three times did Joash beat him (2 Kings 13:25).'),
('2 Kings', 13, 'adults', 7, 'What does the phrase "saviour" (Hebrew moshia) in verse 5 recall about the pattern of Israel''s history?', 'It echoes the language of the judges period where God raised deliverers for an oppressed and repentant people', 'It refers specifically to Elisha who was a type of Christ', 'It points forward to the Messianic king from David''s line', 'It indicates a priestly deliverer like Samuel', 'a', 'The LORD gave Israel a saviour (2 Kings 13:5), using the same term (moshia) found throughout Judges for God''s cycle of judgment, repentance, and deliverance in the history of Israel.'),
('2 Kings', 13, 'adults', 8, 'What is the significance of God''s covenant remembrance with Abraham, Isaac, and Jacob in this context?', 'It shows that national preservation did not depend on Israel''s righteousness but on God''s unconditional patriarchal promises', 'It proves that the Mosaic covenant had been entirely replaced by the Abrahamic', 'It means Israel could sin without consequence because of the covenant', 'It was invoked by Moses at Sinai but has no bearing on later kings', 'a', 'The LORD had compassion on them because of his covenant with Abraham, Isaac, and Jacob (2 Kings 13:23), showing that God''s preservation of sinful Israel rested on His sovereign promise, not their merit.');

-- ═══ 2 Kings Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 14, 'kids', 1, 'What nation did King Amaziah of Judah defeat in the valley of salt?', 'Edom', 'Syria', 'Moab', 'Ammon', 'a', 'He slew of Edom in the valley of salt ten thousand, and took Selah by war (2 Kings 14:7).'),
('2 Kings', 14, 'kids', 2, 'What did Amaziah do to the servants who killed his father Joash?', 'He executed them', 'He forgave them', 'He put them in prison', 'He sold them as slaves', 'a', 'He slew his servants which had slain the king his father (2 Kings 14:5).'),
('2 Kings', 14, 'kids', 3, 'Who restored the border of Israel from the entering of Hamath to the sea of the plain?', 'Jeroboam II', 'Amaziah', 'Uzziah', 'Elisha', 'a', 'He restored the coast of Israel from the entering of Hamath unto the sea of the plain, according to the word of the LORD God of Israel (2 Kings 14:25).'),
-- Teens
('2 Kings', 14, 'teens', 1, 'What was the condition placed on Amaziah''s execution of the conspirators who killed his father?', 'He killed the servants but did not put to death the children of the murderers, according to the law of Moses', 'He killed them only after consulting the high priest', 'He waited until he had reigned ten years before acting', 'He spared them all because he feared a revolt', 'a', 'The children of the murderers he slew not: according unto that which is written in the book of the law of Moses (2 Kings 14:6).'),
('2 Kings', 14, 'teens', 2, 'After his victory over Edom, Amaziah challenged which king to battle?', 'Jehoash the son of Jehoahaz king of Israel', 'Hazael king of Syria', 'Tiglath-pileser king of Assyria', 'Mesha king of Moab', 'a', 'Amaziah sent messengers to Jehoash, the son of Jehoahaz son of Jehu, king of Israel, saying, Come, let us look one another in the face (2 Kings 14:8).'),
('2 Kings', 14, 'teens', 3, 'What parable did Jehoash use to warn Amaziah not to attack him?', 'The thistle of Lebanon asking the cedar for his daughter in marriage, then trampled by a wild beast', 'A weak vine trying to climb a mighty oak and being thrown down', 'A sparrow boasting against an eagle and being devoured', 'A small spring trying to become a great river but drying up', 'a', 'Jehoash said to Amaziah, The thistle that was in Lebanon sent to the cedar...And there passed by a wild beast in Lebanon, and trode down the thistle (2 Kings 14:9).'),
('2 Kings', 14, 'teens', 4, 'What was the result of the battle between Amaziah and Jehoash of Israel at Beth-shemesh?', 'Judah was put to the worse, Amaziah was taken captive, Jerusalem''s wall was broken down', 'Israel was defeated and Jehoash was killed', 'The battle was a draw and both kings agreed to peace', 'Amaziah won a great victory and took much spoil', 'a', 'Judah was put to the worse before Israel; and they fled every man to their tents. And Jehoash king of Israel took Amaziah king of Judah...at Beth-shemesh (2 Kings 14:12-13).'),
('2 Kings', 14, 'teens', 5, 'How long did Jeroboam II reign over Israel in Samaria?', 'Forty and one years', 'Twenty and five years', 'Thirty years', 'Fifty years', 'a', 'Jeroboam...reigned forty and one years in Samaria (2 Kings 14:23).'),
-- Adults
('2 Kings', 14, 'adults', 1, 'What was the spiritual assessment of Amaziah''s reign?', 'He did that which was right in the sight of the LORD, yet not like David his father; he did according to all things as Joash his father did', 'He was fully righteous and removed all the high places', 'He walked in the ways of the kings of Israel making Israel to sin', 'He was the most wicked king Judah had ever seen', 'a', 'He did that which was right in the sight of the LORD, yet not like David his father: he did according to all things as Joash his father did (2 Kings 14:3).'),
('2 Kings', 14, 'adults', 2, 'What specific Mosaic law did Amaziah cite in not killing the children of the assassins?', 'The fathers shall not be put to death for the children, nor the children be put to death for the fathers', 'Every man shall be put to death for his own sin only', 'The children of murderers shall be enslaved but not killed', 'Only the firstborn son of a murderer shall bear his father''s guilt', 'a', 'According to that which is written in the book of the law of Moses, wherein the LORD commanded, saying, The fathers shall not be put to death for the children (2 Kings 14:6; cf. Deuteronomy 24:16).'),
('2 Kings', 14, 'adults', 3, 'How much gold, silver, and goods did Jehoash of Israel take from Jerusalem?', 'All the gold and silver and all the vessels found in the house of the LORD and in the king''s house, and hostages', 'Only the temple treasury and left the palace untouched', 'Ten talents of gold and a hundred talents of silver', 'The ark and the golden altar', 'a', 'He took all the gold and silver, and all the vessels that were found in the house of the LORD, and in the treasures of the king''s house...and returned to Samaria (2 Kings 14:14).'),
('2 Kings', 14, 'adults', 4, 'Through which prophet was the prophecy given concerning Jeroboam II''s restoration of Israel''s borders?', 'Jonah the son of Amittai the prophet, which was of Gath-hepher', 'Amos the herdsman of Tekoa', 'Hosea the son of Beeri', 'Micah the Morasthite', 'a', 'According to the word of the LORD God of Israel, which he spake by the hand of his servant Jonah, the son of Amittai, the prophet, which was of Gath-hepher (2 Kings 14:25).'),
('2 Kings', 14, 'adults', 5, 'What was the theological reason God allowed Jeroboam II to restore Israel''s territory despite his wickedness?', 'The LORD saw the affliction of Israel, that it was very bitter...and had not said he would blot out the name of Israel', 'Jeroboam II had repented late in his reign', 'God was rewarding Israel for the faithfulness of Elisha', 'There was no righteous king available so God used the wicked one', 'a', 'The LORD saw the affliction of Israel, that it was very bitter: for there was not any shut up, nor any left, nor any helper for Israel. And the LORD said not that he would blot out the name of Israel (2 Kings 14:26-27).'),
('2 Kings', 14, 'adults', 6, 'Where was Amaziah eventually killed and how did he die?', 'He fled to Lachish, where a conspiracy was sent after him and he was slain there', 'He died peacefully in Jerusalem of old age', 'He was killed in battle against the Philistines', 'He was executed by his own guard for apostasy', 'a', 'They made a conspiracy against him in Jerusalem: and he fled to Lachish; but they sent after him to Lachish, and slew him there (2 Kings 14:19).'),
('2 Kings', 14, 'adults', 7, 'How much of Jerusalem''s wall did Jehoash of Israel demolish?', 'Four hundred cubits, from the gate of Ephraim unto the corner gate', 'Half the northern wall', 'The entire south wall facing Judah', 'From the fish gate to the valley gate', 'a', 'Jehoash brake down the wall of Jerusalem from the gate of Ephraim unto the corner gate, four hundred cubits (2 Kings 14:13).'),
('2 Kings', 14, 'adults', 8, 'What does the career of Jeroboam II reveal about the relationship between political power and spiritual fidelity in the northern kingdom?', 'God can use even wicked rulers to fulfil His redemptive purposes for His people without endorsing their sin', 'Political success is always a sign of divine approval of the king''s character', 'God abandoned Israel during this period and Jeroboam succeeded by his own military skill', 'The northern kingdom repented under Jeroboam II but later fell back into sin', 'a', 'Jeroboam II did evil in the sight of the LORD yet God used him to save Israel and restore its borders (2 Kings 14:24-27), showing that divine sovereignty operates through and despite human wickedness.');

-- ═══ 2 Kings Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 15, 'kids', 1, 'What disease did King Azariah (Uzziah) have for the rest of his life?', 'Leprosy', 'Blindness', 'Deafness', 'Lameness', 'a', 'The LORD smote the king, so that he was a leper unto the day of his death, and dwelt in a several house (2 Kings 15:5).'),
('2 Kings', 15, 'kids', 2, 'What did Shallum do to become king of Israel?', 'He killed King Zechariah in front of the people', 'He was chosen by the army commanders', 'He was appointed by the high priest', 'He was the son of the previous king', 'a', 'Shallum the son of Jabesh conspired against him, and smote him before the people, and slew him, and reigned in his stead (2 Kings 15:10).'),
('2 Kings', 15, 'kids', 3, 'How long did Shallum reign as king of Israel?', 'One month', 'One year', 'Six months', 'Three years', 'a', 'Shallum the son of Jabesh reigned a full month in Samaria (2 Kings 15:13).'),
-- Teens
('2 Kings', 15, 'teens', 1, 'What happened to Zechariah the son of Jeroboam II, and what prophecy did his death fulfil?', 'He was slain by Shallum, fulfilling that Jehu''s sons would sit on Israel''s throne unto the fourth generation', 'He was deposed and exiled to Assyria', 'He died of plague after a six-month reign', 'He was captured by the Syrians', 'a', 'Shallum slew Zechariah, as the LORD had said unto Jehu, Thy sons shall sit on the throne of Israel unto the fourth generation (2 Kings 15:10, 12).'),
('2 Kings', 15, 'teens', 2, 'What terrible act did Menahem commit against Tiphsah?', 'He smote it and ripped up all the women therein that were with child because they opened not to him', 'He burned it with fire and killed all the men', 'He enslaved its population and sent them to Samaria', 'He destroyed its temple and looted its treasury', 'a', 'Menahem smote Tiphsah...and all the coasts thereof from Tirzah...because they opened not to him, therefore he smote it; and all the women therein that were with child he ripped up (2 Kings 15:16).'),
('2 Kings', 15, 'teens', 3, 'How did Menahem raise the tribute money he paid to Tiglath-pileser of Assyria?', 'He exacted it of Israel, even of all the mighty men of wealth, fifty shekels of silver of every man', 'He emptied the temple treasury', 'He sold northern territories to Assyria', 'He taxed the merchants at the city gates', 'a', 'Menahem exacted the money of Israel, even of all the mighty men of wealth, of each man fifty shekels of silver, to give to the king of Assyria (2 Kings 15:20).'),
('2 Kings', 15, 'teens', 4, 'Which king of Israel was killed by Pekah the son of Remaliah?', 'Pekahiah the son of Menahem', 'Shallum the son of Jabesh', 'Menahem himself', 'Zechariah the son of Jeroboam', 'a', 'Pekah the son of Remaliah, a captain of his, conspired against him, and smote him in Samaria...and killed him, and reigned in his room (2 Kings 15:25).'),
('2 Kings', 15, 'teens', 5, 'Who killed Pekah and became the last king of Israel before its fall?', 'Hoshea the son of Elah', 'Menahem the son of Gadi', 'Tiglath-pileser the Assyrian', 'An unnamed captain from Gilead', 'a', 'Hoshea the son of Elah made a conspiracy against Pekah the son of Remaliah, and smote him, and slew him, and reigned in his stead (2 Kings 15:30).'),
-- Adults
('2 Kings', 15, 'adults', 1, 'Because Azariah was a leper, who judged the people of the land and governed the palace?', 'Jotham the king''s son, who was over the house, judging the people of the land', 'The high priest as regent', 'A council of seventy elders', 'Azariah''s wife as queen regent', 'a', 'Jotham the king''s son was over the house, judging the people of the land (2 Kings 15:5).'),
('2 Kings', 15, 'adults', 2, 'What amount did Menahem pay Tiglath-pileser and what was the Assyrian king''s purpose in accepting it?', 'A thousand talents of silver, that his hand might be with him to confirm the kingdom in his hand', 'Two thousand talents of gold to purchase peace for ten years', 'Fifty shekels per city plus all captured prisoners', 'The entire annual tribute of the temple treasury', 'a', 'Menahem gave Pul a thousand talents of silver, that his hand might be with him to confirm the kingdom in his hand (2 Kings 15:19).'),
('2 Kings', 15, 'adults', 3, 'How many men of wealth contributed to Menahem''s tribute payment, given that each paid fifty shekels?', 'Sixty thousand men, since a thousand talents equals 60,000 times 50 shekels', 'Six hundred thousand, corresponding to the men of the Exodus', 'Ten thousand, matching the fighting force of Israel', 'One thousand, being the mighty men of the guard', 'a', 'A thousand talents of silver at fifty shekels per man requires approximately 60,000 men of wealth, as 1 talent equals 3,000 shekels (2 Kings 15:19-20).'),
('2 Kings', 15, 'adults', 4, 'Where was Pekahiah killed and who assisted Pekah in the assassination?', 'In Samaria in the palace of the king''s house, with Argob and Arieh, and fifty men of the Gileadites', 'In the field at Jezreel with his personal guard', 'At the gate of Samaria by the city elders', 'At Bethel near the golden calf shrine', 'a', 'Pekah smote him in Samaria, in the palace of the king''s house...with Argob and Arieh, and with him fifty men of the Gileadites (2 Kings 15:25).'),
('2 Kings', 15, 'adults', 5, 'What territories did Tiglath-pileser take from Israel during Pekah''s reign?', 'Ijon, Abel-beth-maachah, Janoah, Kedesh, Hazor, Gilead, Galilee, all the land of Naphtali and carried them captive to Assyria', 'Only the Transjordan territories east of the Jordan', 'The coastal plain from Megiddo to Dor', 'Samaria and the hill country of Ephraim', 'a', 'The king of Assyria came, and took Ijon, and Abel-beth-maachah, and Janoah, and Kedesh, and Hazor, and Gilead, and Galilee, all the land of Naphtali, and carried them captive to Assyria (2 Kings 15:29).'),
('2 Kings', 15, 'adults', 6, 'How long did Azariah reign in Jerusalem and what is notable about his age at accession?', 'Fifty and two years; he began to reign at sixteen years old', 'Forty years; he began to reign at twenty', 'Thirty years; he began to reign at twelve', 'Twenty-five years; he began to reign at twenty-five', 'a', 'Azariah was sixteen years old when he began to reign, and he reigned two and fifty years in Jerusalem (2 Kings 15:2).'),
('2 Kings', 15, 'adults', 7, 'What pattern of political instability does chapter 15 reveal about the northern kingdom compared to Judah?', 'Israel had five kings in about thirty years, most dying violently, while Judah had relative stability under Azariah''s long reign', 'Israel was more stable because its kings came from multiple strong dynasties', 'Both kingdoms had equal political instability in this period', 'Judah was more chaotic because Azariah''s leprosy left the kingdom without leadership', 'a', 'In the period of Azariah''s 52-year reign in Judah, Israel cycled through Zechariah, Shallum, Menahem, Pekahiah, and Pekah — most killed violently — demonstrating the instability prophesied for a kingdom without a stable covenant dynasty (2 Kings 15:8-31).'),
('2 Kings', 15, 'adults', 8, 'What does Tiglath-pileser III''s appearance in this chapter signal for the trajectory of the northern kingdom?', 'It marks the beginning of direct Assyrian interference that would culminate in the complete destruction of Samaria in chapter 17', 'It shows that Assyria was merely a neighbouring threat that Israel could manage by paying tribute', 'It fulfils Isaiah''s specific prophecy that Assyria would be Israel''s permanent ally', 'It is the first time a foreign king appears in Kings and sets a precedent of peaceful coexistence', 'a', 'Tiglath-pileser III is paid tribute by Menahem and later depopulates Galilee and Transjordan (2 Kings 15:19, 29), initiating the Assyrian stranglehold on Israel that Sargon II would complete with the fall of Samaria in 722 BC (2 Kings 17).');

-- ═══════════════════════════════════════════
-- CHAPTERS 16 – 20
-- ═══════════════════════════════════════════

-- ═══ 2 Kings Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 16, 'kids', 1, 'Who was the king of Judah in this chapter who did many wicked things?', 'Ahaz the son of Jotham', 'Manasseh the son of Hezekiah', 'Amon', 'Jehoram', 'a', 'Ahaz the son of Jotham king of Judah began to reign (2 Kings 16:1).'),
('2 Kings', 16, 'kids', 2, 'What did Ahaz do with his own son that was very wicked?', 'He made his son pass through the fire', 'He sold his son to Egypt', 'He offered his son to a false prophet', 'He sent his son away to Assyria', 'a', 'He made his son to pass through the fire, according to the abominations of the heathen (2 Kings 16:3).'),
('2 Kings', 16, 'kids', 3, 'Ahaz sent silver and gold from the temple to which powerful king to ask for help?', 'Tiglath-pileser king of Assyria', 'Nebuchadnezzar king of Babylon', 'Pharaoh of Egypt', 'Hazael king of Syria', 'a', 'Ahaz took the silver and gold that was found in the house of the LORD...and sent it for a present to the king of Assyria (2 Kings 16:8).'),
-- Teens
('2 Kings', 16, 'teens', 1, 'What two kings attacked Ahaz of Judah in the Syro-Ephraimite crisis?', 'Rezin king of Syria and Pekah the son of Remaliah king of Israel', 'Hazael of Syria and Menahem of Israel', 'Tiglath-pileser and Shalmaneser of Assyria', 'The king of Egypt and the king of Edom', 'a', 'Rezin king of Syria and Pekah son of Remaliah king of Israel came up to Jerusalem to war (2 Kings 16:5).'),
('2 Kings', 16, 'teens', 2, 'What city did Rezin king of Syria recover for Syria during this crisis?', 'Elath', 'Kadesh', 'Ramoth-gilead', 'Hazor', 'a', 'At that time Rezin king of Syria recovered Elath to Syria, and drave the Jews from Elath (2 Kings 16:6).'),
('2 Kings', 16, 'teens', 3, 'What humiliating title did Ahaz use to describe himself when appealing to Tiglath-pileser for help?', 'I am thy servant and thy son', 'I am thy vassal and thine ally', 'I am the least of thy servants', 'I am a friend to thy house', 'a', 'Ahaz sent messengers to Tiglath-pileser king of Assyria, saying, I am thy servant and thy son: come up, and save me (2 Kings 16:7).'),
('2 Kings', 16, 'teens', 4, 'Where did Ahaz see an altar that he ordered Urijah the priest to copy for Jerusalem?', 'In Damascus', 'In Babylon', 'In Nineveh', 'In Samaria', 'a', 'King Ahaz went to Damascus...and king Ahaz sent to Urijah the priest the fashion of the altar, and the pattern of it, according to all the workmanship thereof (2 Kings 16:10).'),
('2 Kings', 16, 'teens', 5, 'What did Ahaz do to the bronze altar of the LORD after he installed the new Damascus altar?', 'He moved it to the north side and used it only for his own enquiring; the king''s burnt offering was on the new altar', 'He melted it down and sent the bronze to Assyria', 'He had it destroyed entirely', 'He gave it to the priests for personal sacrifices', 'a', 'The brazen altar shall be for me to enquire by. And Urijah the priest did according to all that king Ahaz commanded (2 Kings 16:15).'),
-- Adults
('2 Kings', 16, 'adults', 1, 'How is Ahaz''s wickedness compared to that of other kings in verse 3?', 'He walked in the way of the kings of Israel, and made his son to pass through the fire, after the abominations of the heathen', 'He was more wicked than Manasseh but less wicked than Ahab', 'He did evil like Jeroboam the son of Nebat', 'He sinned in the same manner as Baasha king of Israel', 'a', 'He walked in the way of the kings of Israel, yea, and made his son to pass through the fire, according to the abominations of the heathen (2 Kings 16:3).'),
('2 Kings', 16, 'adults', 2, 'What did Tiglath-pileser do in response to Ahaz''s request and tribute?', 'He hearkened unto him and went up against Damascus and took it and carried the people captive to Kir and slew Rezin', 'He accepted the tribute but did not attack Syria', 'He attacked Israel instead of Syria', 'He promised help but only sent a token force', 'a', 'The king of Assyria hearkened unto him: for the king of Assyria went up against Damascus, and took it, and carried the people of it captive to Kir, and slew Rezin (2 Kings 16:9).'),
('2 Kings', 16, 'adults', 3, 'What changes did Ahaz make to the temple furnishings upon returning from Damascus?', 'He cut off the borders of the bases and removed the laver, took down the sea from the bronze oxen and put it on a stone pavement, and removed the Sabbath canopy', 'He removed only the golden lampstands and sent them to Assyria', 'He destroyed the inner sanctuary and built a new one', 'He relocated the ark of the covenant to the palace treasury', 'a', 'Ahaz cut off the borders of the bases, and removed the laver from off them...and he removed the brasen sea from off the brasen oxen, and put it upon a pavement of stones (2 Kings 16:17).'),
('2 Kings', 16, 'adults', 4, 'What was Ahaz''s stated reason for moving the bronze sea and altering the temple entry?', 'Because of the king of Assyria', 'Because the priests requested it', 'Because the temple floor was cracked', 'Because it was needed for a new religious ceremony', 'a', 'The covert for the sabbath that they had built in the house, and the king''s entry without, turned he from the house of the LORD for the king of Assyria (2 Kings 16:18).'),
('2 Kings', 16, 'adults', 5, 'What does Ahaz''s appeal to Tiglath-pileser as "thy servant and thy son" represent in diplomatic terms?', 'A formal declaration of vassal submission, placing Judah under Assyrian suzerainty', 'A polite diplomatic formula with no binding obligations', 'An adoption ceremony making Ahaz a royal heir of Assyria', 'A military alliance between equals', 'a', 'I am thy servant and thy son (2 Kings 16:7) was standard ancient Near Eastern vassal language, meaning Ahaz formally submitted Judah as a client state of Assyria — a betrayal Isaiah vigorously condemned (cf. Isaiah 7).'),
('2 Kings', 16, 'adults', 6, 'What happened to the Edomites in Elath after Rezin recovered the port city?', 'The Syrians came to Elath and dwelt there unto this day', 'They were expelled and the Israelites returned', 'They allied with Judah against Assyria', 'They were enslaved by the Assyrians', 'a', 'He drave the Jews from Elath: and the Syrians came to Elath, and dwelt there unto this day (2 Kings 16:6).'),
('2 Kings', 16, 'adults', 7, 'What does Urijah the priest''s compliance with Ahaz''s altar orders reveal about the priesthood?', 'The priesthood had become subservient to royal authority, compromising its prophetic role of correcting wayward kings', 'The priests were legally bound to obey the king in all matters of temple organisation', 'Urijah was a false priest who had always been corrupt', 'The Mosaic law permitted the king to redesign temple furnishings', 'a', 'Urijah the priest built an altar according to all that king Ahaz had sent from Damascus...thus did Urijah the priest (2 Kings 16:11), showing a priesthood that failed to stand against royal idolatry as the law required.'),
('2 Kings', 16, 'adults', 8, 'How does Isaiah 7 provide essential background for understanding Ahaz''s choices in this chapter?', 'Isaiah offered Ahaz a sign from God and urged him to trust the LORD rather than Assyria during the Syro-Ephraimite crisis, but Ahaz refused — making his appeal to Tiglath-pileser an act of deliberate unbelief', 'Isaiah approved of Ahaz''s alliance as a necessary political decision', 'Isaiah predicted that Syria and Israel would destroy Judah if Ahaz did not seek Assyrian help', 'Isaiah was silent during Ahaz''s reign and only prophesied under Hezekiah', 'a', 'God through Isaiah told Ahaz "Ask thee a sign of the LORD" (Isaiah 7:11) but Ahaz refused, choosing Tiglath-pileser instead — a decision 2 Kings 16 records as the fulfilment of Ahaz''s faithless policy that ultimately brought Assyria permanently into Judah''s affairs.');

-- ═══ 2 Kings Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 17, 'kids', 1, 'Who was the last king of Israel before it was conquered?', 'Hoshea', 'Pekah', 'Menahem', 'Shallum', 'a', 'In the twelfth year of Ahaz king of Judah began Hoshea the son of Elah to reign in Samaria over Israel (2 Kings 17:1).'),
('2 Kings', 17, 'kids', 2, 'Which great empire took the people of Israel away captive?', 'Assyria', 'Babylon', 'Egypt', 'Persia', 'a', 'The king of Assyria came up throughout all the land, and went up to Samaria, and besieged it three years...and the king of Assyria did carry away Israel unto Assyria (2 Kings 17:5-6).'),
('2 Kings', 17, 'kids', 3, 'What animals did God send to attack the foreign settlers who did not worship Him?', 'Lions', 'Bears', 'Serpents', 'Locusts', 'a', 'The LORD sent lions among them, which slew some of them (2 Kings 17:25).'),
-- Teens
('2 Kings', 17, 'teens', 1, 'How long did Shalmaneser besiege Samaria before it fell?', 'Three years', 'Two years', 'Seven years', 'One year', 'a', 'The king of Assyria besieged it three years (2 Kings 17:5).'),
('2 Kings', 17, 'teens', 2, 'What was the main sin that caused Israel to be exiled, according to the chapter''s explanation?', 'They feared other gods and walked in the statutes of the heathen whom the LORD cast out', 'They refused to pay tribute to Assyria', 'They stopped making sacrifices in the temple', 'They expelled the prophets of the LORD', 'a', 'The children of Israel...feared other gods, and walked in the statutes of the heathen, whom the LORD cast out from before the children of Israel (2 Kings 17:7-8).'),
('2 Kings', 17, 'teens', 3, 'To what place did the Assyrians carry away the Israelites?', 'Halah and Habor by the river of Gozan, and in the cities of the Medes', 'Nineveh and the plains of Assyria', 'Babylon and the land of Shinar', 'Egypt and the desert of Libya', 'a', 'The king of Assyria carried Israel away into Assyria, and put them in Halah and in Habor by the river of Gozan, and in the cities of the Medes (2 Kings 17:6).'),
('2 Kings', 17, 'teens', 4, 'Why did the king of Assyria send back a captured Israelite priest to Bethel?', 'To teach the new settlers the manner of the God of the land, because lions were killing them', 'To translate the law of Moses into their language', 'To maintain peace between the settlers and the Assyrian governor', 'To serve as a political prisoner', 'a', 'The king of Assyria commanded, saying, Carry thither one of the priests whom ye brought from thence; and let them go and dwell there, and let him teach them the manner of the God of the land (2 Kings 17:27-28).'),
('2 Kings', 17, 'teens', 5, 'What was the mixed religious practice of the new settlers called in this chapter?', 'They feared the LORD and served their own gods — they were not true worshippers', 'Syncretism approved by the Assyrian king', 'The way of Samaria accepted by the LORD', 'Partial obedience which pleased God', 'a', 'They feared the LORD, and served their own gods, after the manner of the nations whom they carried away from thence (2 Kings 17:33).'),
-- Adults
('2 Kings', 17, 'adults', 1, 'What act of Hoshea triggered the Assyrian invasion that ended the northern kingdom?', 'He sent messengers to So king of Egypt and brought no present to the king of Assyria as he had done year by year', 'He stopped worshipping the golden calves at Bethel and Dan', 'He made an alliance with Damascus against Assyria', 'He invaded Judah seeking to unite the kingdoms', 'a', 'Hoshea sent messengers to So king of Egypt, and brought no present to the king of Assyria, as he had done year by year: therefore the king of Assyria shut him up, and bound him in prison (2 Kings 17:4).'),
('2 Kings', 17, 'adults', 2, 'What does the phrase "the LORD was very angry with Israel, and removed them out of his sight" echo from earlier in Kings?', 'The repeated prophetic warnings from Moses and the prophets that covenant unfaithfulness would result in exile from the land', 'The curse of Balaam on Israel in the wilderness', 'The prayer of Solomon at the temple dedication that God would forgive if they sinned', 'The threat made by Elijah to Ahab after the vineyard of Naboth', 'a', 'The LORD was very angry with Israel, and removed them out of his sight (2 Kings 17:18), fulfilling the curses of Deuteronomy 28-29 and the repeated warnings of prophets sent to Israel (2 Kings 17:13).'),
('2 Kings', 17, 'adults', 3, 'What people groups were settled in the cities of Samaria to replace the exiled Israelites?', 'From Babylon, and from Cuthah, and from Ava, and from Hamath, and from Sepharvaim', 'From Nineveh and the cities of Persia', 'From Moab, Edom, and the Philistine plain', 'From Egypt and the western coast of the Mediterranean', 'a', 'The king of Assyria brought men from Babylon, and from Cuthah, and from Ava, and from Hamath, and from Sepharvaim, and placed them in the cities of Samaria (2 Kings 17:24).'),
('2 Kings', 17, 'adults', 4, 'What gods did the men of Babylon and Cuth bring with them to Samaria?', 'Succoth-benoth; the men of Cuth made Nergal', 'Baal and Asherah from their homeland', 'Chemosh and Milcom from Moab and Ammon', 'Dagon and Ashtaroth from the coastal Philistines', 'a', 'The men of Babylon made Succoth-benoth, and the men of Cuth made Nergal, and the men of Hamath made Ashima (2 Kings 17:30).'),
('2 Kings', 17, 'adults', 5, 'What specific sin does the narrator emphasise that Jeroboam drove Israel into, and why was it so significant?', 'He made Israel walk in all his sins, driving them away from following the LORD with two golden calves at Bethel and Dan — a cultic perversion that persisted until the exile', 'He introduced human sacrifice which was the final cause of exile', 'He removed the ark of the covenant from Jerusalem', 'He made Israel abandon the Sabbath entirely', 'a', 'They followed the sins of Jeroboam the son of Nebat...and the children of Israel did secretly those things that were not right against the LORD...even from the tower of the watchmen to the fenced city (2 Kings 17:22, 9).'),
('2 Kings', 17, 'adults', 6, 'How many gods did the new settler population of Samaria ultimately worship alongside the LORD?', 'They feared the LORD yet served their own gods — a dual worship the text condemns as not true fear of the LORD', 'They abandoned all foreign gods after the lions attacked them', 'They served only the LORD after the priest taught them', 'They worshipped three gods in rotation', 'a', 'They fear not the LORD, neither do they after their statutes, or after their ordinances, or after the law and commandment which the LORD commanded the children of Jacob (2 Kings 17:34).'),
('2 Kings', 17, 'adults', 7, 'What does the phrase "unto this day" (used repeatedly in chapter 17) tell us about the author''s perspective?', 'The narrator was writing after the exile and could observe that the syncretistic practices of the Samaritan settlers were still ongoing', 'The narrator was an eyewitness of the Assyrian conquest writing immediately after', 'The phrase indicates the events were very recent', 'The phrase is a scribal addition from a later editor with no theological significance', 'a', 'So do they unto this day (2 Kings 17:41) shows the narrator writing from a post-exilic perspective, confirming the ongoing Samaritan syncretism as still present in his day.'),
('2 Kings', 17, 'adults', 8, 'What theological purpose does the extended commentary in verses 7-23 serve in the book of Kings as a whole?', 'It provides a definitive theological verdict on the northern kingdom''s history, explaining that exile was the just result of centuries of covenant faithlessness despite divine patience and prophetic warning', 'It is an editorial aside with no bearing on the narrative of Judah', 'It simply records historical facts without theological interpretation', 'It primarily blames the Assyrian empire rather than Israel''s sin', 'a', 'The commentary of 2 Kings 17:7-23 is the theological climax of the northern kingdom narrative, demonstrating that Samaria''s fall was not a military accident but the fulfilment of covenantal curses (Deuteronomy 28) long threatened through every prophet God sent to Israel (2 Kings 17:13).');

-- ═══ 2 Kings Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 18, 'kids', 1, 'What king of Judah trusted in the LORD and removed the high places and broke down the idols?', 'Hezekiah', 'Josiah', 'David', 'Solomon', 'a', 'Hezekiah...removed the high places, and brake the images, and cut down the groves, and brake in pieces the brasen serpent that Moses had made (2 Kings 18:3-4).'),
('2 Kings', 18, 'kids', 2, 'What did Hezekiah break into pieces because the people were burning incense to it?', 'The brasen serpent that Moses had made', 'The golden calf at Bethel', 'An Asherah pole in the temple', 'The altar at the high place', 'a', 'He brake in pieces the brasen serpent that Moses had made: for unto those days the children of Israel did burn incense to it (2 Kings 18:4).'),
('2 Kings', 18, 'kids', 3, 'What was the name of the Assyrian officer who came and spoke against Hezekiah and the LORD?', 'Rabshakeh', 'Sennacherib', 'Tiglath-pileser', 'Shalmaneser', 'a', 'The king of Assyria sent Rabshakeh from Lachish to Jerusalem unto king Hezekiah with a great host (2 Kings 18:17).'),
-- Teens
('2 Kings', 18, 'teens', 1, 'What is the spiritual summary given of Hezekiah''s character?', 'He trusted in the LORD God of Israel; so that after him was none like him among all the kings of Judah, nor any that were before him', 'He was as righteous as David but fell short of Solomon in wisdom', 'He did right but did not remove the high places', 'He followed the LORD only in the early years of his reign', 'a', 'He trusted in the LORD God of Israel; so that after him was none like him among all the kings of Judah, nor any that were before him (2 Kings 18:5).'),
('2 Kings', 18, 'teens', 2, 'What were the two things Hezekiah refused to do in relation to the king of Assyria?', 'He rebelled against the king of Assyria and served him not', 'He paid tribute and refused military alliance', 'He hid in the temple and refused to negotiate', 'He surrendered the temple treasury but refused to open the city gates', 'a', 'He rebelled against the king of Assyria, and served him not (2 Kings 18:7).'),
('2 Kings', 18, 'teens', 3, 'How much tribute did Hezekiah initially give Sennacherib after his invasion of Judah?', 'Three hundred talents of silver and thirty talents of gold', 'A thousand talents of silver and a hundred talents of gold', 'Fifty talents each of silver and gold', 'Two hundred talents of silver and fifty of gold', 'a', 'Hezekiah gave him three hundred talents of silver and thirty talents of gold (2 Kings 18:14).'),
('2 Kings', 18, 'teens', 4, 'What claim did Rabshakeh make about the LORD''s role in the Assyrian invasion?', 'The LORD said to me, Go up against this land, and destroy it', 'The LORD has abandoned Hezekiah because he destroyed the high places', 'The gods of all nations are powerless against Assyria', 'The LORD cannot hear prayers from within Jerusalem''s walls', 'a', 'Rabshakeh said, Am I now come up without the LORD against this place to destroy it? The LORD said to me, Go up against this land, and destroy it (2 Kings 18:25).'),
('2 Kings', 18, 'teens', 5, 'Why did Hezekiah''s officials ask Rabshakeh to speak in the Syrian language rather than the Jews'' language?', 'So that the people on the wall would not hear and be frightened', 'So that spies from Assyria could not understand the reply', 'Because Hebrew was considered a sacred language not to be used in negotiations', 'So that the negotiations could be kept secret from the priests', 'a', 'Speak, I pray thee, to thy servants in the Syrian language...and talk not with us in the Jews'' language in the ears of the people that are on the wall (2 Kings 18:26).'),
-- Adults
('2 Kings', 18, 'adults', 1, 'What Mosaic artefact did Hezekiah destroy and what name did he give it?', 'The bronze serpent that Moses had made, calling it Nehushtan', 'The tent of meeting that had been in Shiloh', 'The golden ephod of Gideon that Israel had made an idol', 'The stone tablets of the law that were cracked', 'a', 'He brake in pieces the brasen serpent that Moses had made: for unto those days the children of Israel did burn incense to it: and he called it Nehushtan (2 Kings 18:4).'),
('2 Kings', 18, 'adults', 2, 'How did Hezekiah strip the temple to pay Sennacherib''s tribute demand?', 'He cut off the gold from the doors of the temple of the LORD, and from the pillars which Hezekiah king of Judah had overlaid, and gave it to the king of Assyria', 'He melted the golden lampstands and the altar of incense', 'He sold the priestly vestments and the silver basins', 'He removed the ark of the covenant and gave it as a pledge', 'a', 'Hezekiah cut off the gold from the doors of the temple of the LORD, and from the pillars which Hezekiah king of Judah had overlaid, and gave it to the king of Assyria (2 Kings 18:16).'),
('2 Kings', 18, 'adults', 3, 'What four arguments did Rabshakeh make against Judah''s ability to withstand Assyria?', 'Egypt is a broken reed, Hezekiah destroyed the LORD''s own altars, Judah lacks horses, and the LORD commanded Assyria to come', 'Judah''s army is weak, its walls are old, its allies have all fallen, and its food supply is cut off', 'Hezekiah is a false king, the priests are corrupt, the people are unfaithful, and God is angry with Jerusalem', 'Assyria has never been defeated, its gods are the strongest, its army is the largest, and surrender is the only reasonable choice', 'a', 'Rabshakeh argued: Egypt is a broken reed (v.21); Hezekiah has removed the LORD''s high places (v.22); Judah cannot supply horsemen for even two thousand horses (v.23); the LORD commanded this invasion (v.25) (2 Kings 18:21-25).'),
('2 Kings', 18, 'adults', 4, 'What did Rabshakeh promise the people of Jerusalem if they surrendered?', 'A land like your own land, a land of corn and wine, a land of bread and vineyards, a land of oil olive and of honey, that ye may live, and not die', 'Safe passage to the cities of Judah unharmed', 'Freedom from taxation for thirty years', 'They could keep their property and return within two generations', 'a', 'Hearken not to Hezekiah: for thus saith the king of Assyria, Make an agreement with me by a present, and come out to me, and then eat ye every man of his own vine...until I come and take you away to a land like your own land (2 Kings 18:31-32).'),
('2 Kings', 18, 'adults', 5, 'How did the people of Jerusalem respond to Rabshakeh''s speech?', 'They answered him not a word: for the king''s commandment was, saying, Answer him not', 'They shouted defiance from the walls', 'They wept and begged Hezekiah to surrender', 'They threw stones at the Assyrian delegation', 'a', 'The people held their peace, and answered him not a word: for the king''s commandment was, saying, Answer him not (2 Kings 18:36).'),
('2 Kings', 18, 'adults', 6, 'What is the significance of Rabshakeh''s comparison of the LORD to the gods of other nations?', 'It constitutes a direct blasphemy, setting up the theological confrontation resolved in chapter 19 where the LORD demonstrates his uniqueness over all gods', 'It was simply a diplomatic rhetorical strategy with no religious significance', 'Rabshakeh was himself a believer who misquoted the LORD', 'It proved that Assyria had already defeated the god of Jerusalem', 'a', 'Rabshakeh said, Hath any of the gods of the nations delivered at all his land out of the hand of the king of Assyria? (2 Kings 18:33) — this challenge to the LORD''s uniqueness sets up Hezekiah''s prayer and the divine response in chapter 19.'),
('2 Kings', 18, 'adults', 7, 'How did Hezekiah''s officials react when they returned to him after hearing Rabshakeh?', 'They came to Hezekiah with their clothes rent and told him the words of Rabshakeh', 'They resigned their positions out of fear', 'They convened the elders to plan a surrender', 'They sent a secret messenger to Egypt', 'a', 'They came to Hezekiah with their clothes rent, and told him the words of Rabshakeh (2 Kings 18:37).'),
('2 Kings', 18, 'adults', 8, 'What theological irony is present in Rabshakeh''s claim that the LORD commanded Assyria to attack, in light of the book of Isaiah?', 'The claim contains a grain of truth — God did use Assyria as an instrument of judgment — but Rabshakeh twisted it into a counsel of despair, while Isaiah affirmed God would also judge Assyria for its arrogance', 'Rabshakeh''s claim was entirely false and the LORD never used Assyria for any divine purpose', 'The claim correctly summarises Isaiah''s entire prophecy', 'Rabshakeh was a secret Hebrew prophet preaching surrender as the will of God', 'a', 'Isaiah 10:5-6 confirms that Assyria was indeed the rod of God''s anger against sinful Israel, but Assyria exceeded its mandate through pride — so while Rabshakeh''s claim had theological basis (cf. 2 Kings 18:25), Isaiah 10:12-16 records God''s judgment on Assyria for its arrogance.');

-- ═══ 2 Kings Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 19, 'kids', 1, 'What did Hezekiah do when he heard the threatening words of Assyria?', 'He went into the house of the LORD', 'He hid in the palace', 'He gathered his army', 'He wrote a letter to Egypt', 'a', 'When king Hezekiah heard it, that he rent his clothes, and covered himself with sackcloth, and went into the house of the LORD (2 Kings 19:1).'),
('2 Kings', 19, 'kids', 2, 'Which prophet did Hezekiah send to for help against the Assyrians?', 'Isaiah', 'Elijah', 'Jeremiah', 'Micah', 'a', 'He sent Eliakim...unto Isaiah the prophet the son of Amoz (2 Kings 19:2).'),
('2 Kings', 19, 'kids', 3, 'How many Assyrian soldiers did the angel of the LORD kill in one night?', 'A hundred and eighty-five thousand', 'A hundred thousand', 'Ten thousand', 'Fifty thousand', 'a', 'The angel of the LORD went out, and smote in the camp of the Assyrians a hundred fourscore and five thousand (2 Kings 19:35).'),
-- Teens
('2 Kings', 19, 'teens', 1, 'What did Isaiah tell Hezekiah''s messengers about Sennacherib''s fate?', 'He shall hear a rumour, and shall return to his own land; and I will cause him to fall by the sword in his own land', 'He shall be struck blind and wander in the wilderness', 'His army shall be destroyed by plague and he shall flee to Nineveh', 'He shall be defeated in battle outside Jerusalem''s walls', 'a', 'Thus saith the LORD, Be not afraid of the words which thou hast heard...Behold, I will send a blast upon him, and he shall hear a rumour, and shall return to his own land; and I will cause him to fall by the sword in his own land (2 Kings 19:6-7).'),
('2 Kings', 19, 'teens', 2, 'What key theological claim did Hezekiah make in his prayer about the gods of the other nations?', 'They are no gods, but the work of men''s hands, wood and stone', 'They are demons who deceive the nations', 'They are fallen angels who rule the nations', 'They have some power but the LORD is greater', 'a', 'Of a truth, LORD, the kings of Assyria have destroyed the nations and their lands, and have cast their gods into the fire: for they were no gods, but the work of men''s hands, wood and stone (2 Kings 19:17-18).'),
('2 Kings', 19, 'teens', 3, 'What was the sign Isaiah gave regarding the survival of Judah?', 'Ye shall eat this year such things as grow of themselves, and in the second year that which springeth of the same; and in the third year sow ye', 'A star would appear over Jerusalem for three nights', 'The walls of the city would shine with light for forty days', 'Rain would fall in the dry season as proof of deliverance', 'a', 'And this shall be a sign unto thee, Ye shall eat this year such things as grow of themselves, and in the second year that which springeth of the same; and in the third year sow ye, and reap (2 Kings 19:29).'),
('2 Kings', 19, 'teens', 4, 'How did Sennacherib die, and who killed him?', 'He was slain by his sons Adrammelech and Sharezer with the sword while worshipping in the house of Nisroch his god', 'He died of a plague that swept through Nineveh', 'He was executed by Esarhaddon for losing his army', 'He died peacefully of old age in Nineveh', 'a', 'It came to pass, as he was worshipping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword (2 Kings 19:37).'),
('2 Kings', 19, 'teens', 5, 'What image did Isaiah use to describe Sennacherib''s arrogance before God?', 'He had boasted with the height of the mountains and thought himself the axe that could boast against him that heweth', 'He compared himself to the sun rising over all the earth', 'He claimed to be greater than the gods of heaven', 'He said his arm was stronger than the arm of the LORD', 'a', 'By the multitude of my chariots I am come up to the height of the mountains...I have digged and drunk strange waters (2 Kings 19:23-24), showing Sennacherib''s boast that his own power accomplished everything.'),
-- Adults
('2 Kings', 19, 'adults', 1, 'How did Hezekiah physically handle Sennacherib''s threatening letter?', 'He went up into the house of the LORD, and spread it before the LORD', 'He tore it in pieces and returned it to the messengers', 'He gave it to Isaiah for interpretation', 'He posted it on the city gates as a warning to the people', 'a', 'Hezekiah received the letter of the hand of the messengers, and read it: and Hezekiah went up into the house of the LORD, and spread it before the LORD (2 Kings 19:14).'),
('2 Kings', 19, 'adults', 2, 'What theological basis did Hezekiah use as the foundation of his prayer for deliverance?', 'That the LORD alone is God of all the kingdoms of the earth, thou hast made heaven and earth', 'That Israel had kept the covenant faithfully for three generations', 'That Solomon''s temple was the most holy place on earth', 'That the Davidic promise guaranteed Jerusalem''s protection', 'a', 'Hezekiah prayed, O LORD God of Israel, which dwellest between the cherubims, thou art the God, even thou alone, of all the kingdoms of the earth; thou hast made heaven and earth (2 Kings 19:15).'),
('2 Kings', 19, 'adults', 3, 'What does Isaiah''s oracle say the LORD had purposed long before Sennacherib''s campaigns?', 'Hast thou not heard long ago how I have done it, and of ancient times that I have formed it? now have I brought it to pass', 'The LORD had not planned Assyria''s campaigns but was permitting them', 'Sennacherib''s victories were entirely due to his own military genius', 'God had warned Sennacherib not to attack but he refused', 'a', 'Hast thou not heard long ago how I have done it, and of ancient times that I have formed it? now have I brought it to pass (2 Kings 19:25), showing that Assyria''s campaigns were within God''s sovereign plan.'),
('2 Kings', 19, 'adults', 4, 'What specific insult to God does Isaiah''s oracle identify as provoking divine action against Sennacherib?', 'By thy messengers thou hast reproached the LORD, and hast said, With the multitude of my chariots I am come up to the height of the mountains', 'He dared to approach the gates of Jerusalem which was God''s holy city', 'He demanded tribute from the temple treasury', 'He claimed to be a god equal to the LORD', 'a', 'By thy messengers thou hast reproached the LORD, and hast said, With the multitude of my chariots I am come up to the height of the mountains, to the sides of Lebanon (2 Kings 19:23).'),
('2 Kings', 19, 'adults', 5, 'What divine promise does Isaiah make about the remnant of the house of Judah?', 'The remnant that is escaped of the house of Judah shall yet again take root downward, and bear fruit upward', 'Jerusalem shall be utterly destroyed but rebuilt in forty years', 'The remnant shall go into exile but return in seventy years', 'The house of David shall rule forever without interruption', 'a', 'The remnant that is escaped of the house of Judah shall yet again take root downward, and bear fruit upward (2 Kings 19:30).'),
('2 Kings', 19, 'adults', 6, 'What four-part promise did the LORD make about what Sennacherib would NOT do to Jerusalem?', 'He shall not come into this city, nor shoot an arrow there, nor come before it with shield, nor cast a bank against it', 'He shall not enter the temple, touch the ark, harm the priests, or defile the altar', 'He shall not kill the king, enslave the people, burn the temple, or break the walls', 'He shall not destroy the city, remove the people, take the treasure, or cut down the trees', 'a', 'He shall not come into this city, nor shoot an arrow there, nor come before it with shield, nor cast a bank against it (2 Kings 19:32).'),
('2 Kings', 19, 'adults', 7, 'What does the phrase "for my own sake, and for my servant David''s sake" reveal about God''s motivation for defending Jerusalem?', 'God''s defence of Jerusalem rested simultaneously on His own honour and on the Davidic covenant — not merely on Hezekiah''s righteousness', 'God defended Jerusalem only because Hezekiah was personally righteous', 'The Davidic covenant had no bearing and God acted purely to preserve His temple', 'God''s sole motivation was to demonstrate His power to Assyria and Egypt', 'a', 'I will defend this city, to save it, for mine own sake, and for my servant David''s sake (2 Kings 19:34), showing that the defence rested on God''s own name and His covenant with David (2 Samuel 7).'),
('2 Kings', 19, 'adults', 8, 'What does the destruction of 185,000 Assyrians by a single angel demonstrate theologically about divine warfare?', 'God requires no human army to accomplish His purposes; one heavenly agent is sufficient against the world''s greatest military power', 'It proves that Jerusalem had a larger garrison than Assyria realised', 'It shows that plagues are God''s primary instrument against wicked nations', 'It demonstrates the superiority of Israelite military strategy under Hezekiah', 'a', 'The angel of the LORD smote in the camp of the Assyrians a hundred fourscore and five thousand (2 Kings 19:35), showing that the LORD of hosts fights for His people without requiring human military strength, echoing the divine warrior theme throughout Scripture.');

-- ═══ 2 Kings Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Kings', 20, 'kids', 1, 'What happened to Hezekiah that made him very sick and almost die?', 'He was sick unto death', 'He was bitten by a serpent', 'He fell from the temple wall', 'He was wounded in battle', 'a', 'In those days was Hezekiah sick unto death (2 Kings 20:1).'),
('2 Kings', 20, 'kids', 2, 'How many extra years did God promise to add to Hezekiah''s life after he prayed?', 'Fifteen years', 'Ten years', 'Twenty years', 'Seven years', 'a', 'I have heard thy prayer, I have seen thy tears: behold, I will heal thee: on the third day thou shalt go up unto the house of the LORD. And I will add unto thy days fifteen years (2 Kings 20:5-6).'),
('2 Kings', 20, 'kids', 3, 'What sign did God perform with the sundial to confirm His promise to Hezekiah?', 'He made the shadow go backward ten degrees', 'He made the sun shine through the night', 'He made the shadow stand still for one hour', 'He turned the shadow to gold', 'a', 'He brought the shadow ten degrees backward, by which it had gone down in the dial of Ahaz (2 Kings 20:11).'),
-- Teens
('2 Kings', 20, 'teens', 1, 'What was Hezekiah told by Isaiah before God extended his life?', 'Set thine house in order; for thou shalt die, and not live', 'Repent of thy sins or die before the year is out', 'Surrender to Assyria or be taken into captivity', 'Make a sacrifice at the temple or the LORD will not hear thy prayer', 'a', 'Isaiah said unto him, Thus saith the LORD, Set thine house in order; for thou shalt die, and not live (2 Kings 20:1).'),
('2 Kings', 20, 'teens', 2, 'What did Hezekiah do after receiving Isaiah''s death sentence?', 'He turned his face to the wall, and prayed unto the LORD, and wept sore', 'He called a fast for all Jerusalem', 'He offered a great sacrifice at the temple', 'He summoned all the elders to pray with him', 'a', 'Then he turned his face to the wall, and prayed unto the LORD, saying...And Hezekiah wept sore (2 Kings 20:2-3).'),
('2 Kings', 20, 'teens', 3, 'What was the poultice prescribed to heal Hezekiah''s boil?', 'A lump of figs laid upon the boil', 'A mixture of oil and wine applied with a cloth', 'Cedar bark soaked in water', 'Ground hyssop mixed with honey', 'a', 'Isaiah said, Take a lump of figs. And they took and laid it on the boil, and he recovered (2 Kings 20:7).'),
('2 Kings', 20, 'teens', 4, 'From which country did messengers come bearing letters and a present for Hezekiah?', 'Babylon, sent by Berodach-baladan the son of Baladan', 'Egypt, sent by the Pharaoh', 'Persia, sent by Cyrus', 'Syria, sent by the new king of Damascus', 'a', 'Berodach-baladan, the son of Baladan, king of Babylon, sent letters and a present unto Hezekiah: for he had heard that Hezekiah had been sick (2 Kings 20:12).'),
('2 Kings', 20, 'teens', 5, 'What warning did Isaiah give Hezekiah after he showed the Babylonian envoys all his treasures?', 'Behold, the days come, that all that is in thine house...shall be carried into Babylon: nothing shall be left', 'The Babylonians will return in ten years to destroy Jerusalem', 'God will strike Hezekiah with leprosy for showing his wealth to foreigners', 'The Babylonian king will make war on Judah within one generation', 'a', 'Isaiah said, Behold, the days come, that all that is in thine house, and that which thy fathers have laid up in store unto this day, shall be carried into Babylon: nothing shall be left, saith the LORD (2 Kings 20:17).'),
-- Adults
('2 Kings', 20, 'adults', 1, 'On what basis did Hezekiah appeal to God in his prayer for healing?', 'I beseech thee, O LORD, remember now how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight', 'On the basis of the Davidic covenant and his descent from the king after God''s own heart', 'He promised to give the entire temple treasury as an offering if healed', 'He reminded God of his having destroyed the brazen serpent and removed the high places', 'a', 'Hezekiah prayed, I beseech thee, O LORD, remember now how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept sore (2 Kings 20:3).'),
('2 Kings', 20, 'adults', 2, 'How quickly did God reverse His word to Hezekiah through Isaiah?', 'Before Isaiah had gone out into the middle court, the word of the LORD came to him again', 'On the following morning after Hezekiah''s prayer', 'Three days later when Hezekiah entered the temple', 'Seven days of prayer and fasting later', 'a', 'It came to pass, afore Isaiah was gone out into the middle court, that the word of the LORD came to him, saying, Turn again (2 Kings 20:4).'),
('2 Kings', 20, 'adults', 3, 'What title did God use for Himself in Isaiah''s message that revealed the covenantal basis for hearing Hezekiah''s prayer?', 'The LORD, the God of David thy father', 'The LORD of hosts, the Holy One of Israel', 'The LORD your God who brought you out of Egypt', 'The God of Abraham, Isaac, and Jacob', 'a', 'Thus saith the LORD, the God of David thy father (2 Kings 20:5), grounding the healing promise in the Davidic covenant.'),
('2 Kings', 20, 'adults', 4, 'Which of the two sign options did Hezekiah choose and why did he make that choice?', 'He chose the shadow going backward rather than forward, saying it is a light thing for the shadow to go down ten degrees', 'He chose the shadow going forward as a more natural sign', 'He left the choice to Isaiah the prophet', 'He refused a sign saying he trusted God without confirmation', 'a', 'Hezekiah answered, It is a light thing for the shadow to go down ten degrees: nay, but let the shadow return backward ten degrees. And Isaiah the prophet cried unto the LORD: and he brought the shadow ten degrees backward (2 Kings 20:10-11).'),
('2 Kings', 20, 'adults', 5, 'What did Hezekiah show the Babylonian envoys that provoked Isaiah''s condemnation?', 'All the house of his precious things, the silver, and the gold, and the spices, and the precious ointment, and all the house of his armour, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah shewed them not', 'Only the temple treasury and the new bronze altar', 'The plans for Jerusalem''s fortifications and water supply', 'The ark of the covenant and the priestly garments', 'a', 'Hezekiah shewed them all the house of his precious things, the silver, and the gold, and the spices, and the precious ointment, and all the house of his armour, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah shewed them not (2 Kings 20:13).'),
('2 Kings', 20, 'adults', 6, 'What would happen to Hezekiah''s sons according to Isaiah''s prophecy?', 'They shall be taken away; and they shall be eunuchs in the palace of the king of Babylon', 'They shall rule Israel and Judah as co-regents', 'They shall be killed when Babylon destroys Jerusalem', 'They shall go into Egypt and serve the Pharaoh', 'a', 'Of thy sons that shall issue from thee...shall they take away; and they shall be eunuchs in the palace of the king of Babylon (2 Kings 20:18).'),
('2 Kings', 20, 'adults', 7, 'How did Hezekiah respond to Isaiah''s prophecy of Babylonian exile?', 'Good is the word of the LORD...Is it not good, if peace and truth be in my days?', 'He tore his robe and cried to God for mercy on his descendants', 'He repented in sackcloth and the prophecy was cancelled', 'He imprisoned Isaiah for speaking such words against the king''s house', 'a', 'Hezekiah said unto Isaiah, Good is the word of the LORD which thou hast spoken. And he said, Is it not good, if peace and truth be in my days? (2 Kings 20:19).'),
('2 Kings', 20, 'adults', 8, 'What does Hezekiah''s tunnel and pool, mentioned in verse 20, represent historically?', 'An extraordinary feat of engineering — the Siloam Tunnel — confirmed by archaeology and a discovered inscription, dug to secure Jerusalem''s water supply during the Assyrian siege', 'A symbolic water offering to the LORD made during Hezekiah''s sickness', 'The irrigation system built during the fifteen added years', 'A defensive moat dug around Jerusalem''s walls', 'a', 'He made a pool, and a conduit, and brought water into the city (2 Kings 20:20). The Siloam Tunnel (Hezekiah''s Tunnel) was discovered in the 19th century, and the Siloam Inscription found within it confirms the biblical account of its construction.');
